// Parse OpenAI API response for NFR test analysis
const response = $input.first().json;

// Extract the message content from OpenAI response structure
const aiContent = response.choices?.[0]?.message?.content || '{}';

let aiAnalysis = {};
try {
  // Try to parse JSON from the response
  const jsonMatch = aiContent.match(/```json\n?([\s\S]*?)\n?```/) || 
                    aiContent.match(/\{[\s\S]*\}/);
  aiAnalysis = JSON.parse(jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : aiContent);
} catch (e) {
  aiAnalysis = {
    analysis: { issues: [] },
    loadTestConfig: {},
    stressTestConfig: {},
    spikeTestConfig: {},
    enduranceTestConfig: {},
    breakpointTestConfig: {},
    customMetrics: [],
    slaDefinitions: [],
    parseError: e.message,
    rawContent: aiContent
  };
}

return [{
  json: {
    aiAnalysis,
    tokensUsed: response.usage?.total_tokens || 0,
    phase: 'nfr-ai-analysis-complete'
  }
}];

// Generate k6 test scripts for all NFR test types
const aiAnalysisData = $input.first().json;
const aiAnalysis = aiAnalysisData.aiAnalysis || {};

// Load Test Script
const loadTestScript = `
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend, Counter } from 'k6/metrics';

// Custom metrics
const errorRate = new Rate('errors');
const responseTime = new Trend('response_time');
const requestCount = new Counter('request_count');

export const options = {
  scenarios: {
    load_test: {
      executor: 'constant-vus',
      vus: ${aiAnalysis.loadTestConfig?.vus || 50},
      duration: '${aiAnalysis.loadTestConfig?.duration || '5m'}',
    },
  },
  thresholds: {
    http_req_duration: ['p(95)<500', 'p(99)<1000'],
    http_req_failed: ['rate<0.05'],
    errors: ['rate<0.1'],
    http_reqs: ['rate>100'],
  },
};

export default function () {
  const res = http.get('http://localhost:3000/api/health');
  check(res, {
    'status is 200': (r) => r.status === 200,
    'response time < 500ms': (r) => r.timings.duration < 500,
  });
  errorRate.add(res.status !== 200);
  responseTime.add(res.timings.duration);
  requestCount.add(1);
  sleep(1);
}
`;

// Stress Test Script  
const stressTestScript = `
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend } from 'k6/metrics';

const errorRate = new Rate('errors');

export const options = {
  scenarios: {
    stress_test: {
      executor: 'ramping-vus',
      startVUs: 0,
      stages: [
        { duration: '2m', target: 50 },   // Ramp up to normal load
        { duration: '5m', target: 50 },   // Stay at normal load
        { duration: '2m', target: 100 },  // Ramp up to high load
        { duration: '5m', target: 100 },  // Stay at high load
        { duration: '2m', target: 200 },  // Ramp up to stress load
        { duration: '5m', target: 200 },  // Stay at stress load
        { duration: '2m', target: 300 },  // Ramp up to breaking point
        { duration: '5m', target: 300 },  // Stay at breaking point
        { duration: '5m', target: 0 },    // Ramp down
      ],
    },
  },
  thresholds: {
    http_req_duration: ['p(95)<1000'],
    http_req_failed: ['rate<0.1'],
    errors: ['rate<0.15'],
  },
};

export default function () {
  const res = http.get('http://localhost:3000/api/health');
  check(res, {
    'status is 200': (r) => r.status === 200,
    'response time < 1000ms': (r) => r.timings.duration < 1000,
  });
  errorRate.add(res.status !== 200);
  sleep(0.5);
}
`;

// Spike Test Script
const spikeTestScript = `
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate } from 'k6/metrics';

const errorRate = new Rate('errors');

export const options = {
  scenarios: {
    spike_test: {
      executor: 'ramping-vus',
      startVUs: 0,
      stages: [
        { duration: '1m', target: 10 },    // Normal load
        { duration: '30s', target: 500 },   // Spike!
        { duration: '1m', target: 500 },    // Stay at spike
        { duration: '30s', target: 10 },    // Recovery
        { duration: '2m', target: 10 },     // Monitor recovery
        { duration: '30s', target: 500 },   // Second spike
        { duration: '1m', target: 500 },    // Stay at spike
        { duration: '1m', target: 0 },      // Ramp down
      ],
    },
  },
  thresholds: {
    http_req_duration: ['p(95)<2000'],
    http_req_failed: ['rate<0.15'],
  },
};

export default function () {
  const res = http.get('http://localhost:3000/api/health');
  check(res, {
    'status is 200': (r) => r.status === 200,
  });
  errorRate.add(res.status !== 200);
  sleep(0.3);
}
`;

// Endurance/Soak Test Script
const enduranceTestScript = `
import http from 'k6/http';
import { check, sleep } from 'k6';
import { Rate, Trend, Gauge } from 'k6/metrics';

const errorRate = new Rate('errors');
const memoryUsage = new Gauge('memory_usage_trend');

export const options = {
  scenarios: {
    endurance_test: {
      executor: 'constant-vus',
      vus: ${aiAnalysis.enduranceTestConfig?.vus || 30},
      duration: '${aiAnalysis.enduranceTestConfig?.duration || '30m'}', // Extended duration for soak testing
    },
  },
  thresholds: {
    http_req_duration: ['p(95)<800', 'p(99)<1500'],
    http_req_failed: ['rate<0.05'],
    errors: ['rate<0.05'],
  },
};

export default function () {
  const res = http.get('http://localhost:3000/api/health');
  check(res, {
    'status is 200': (r) => r.status === 200,
    'response time stable': (r) => r.timings.duration < 800,
    'no memory leak indicators': (r) => r.timings.duration < 1500,
  });
  errorRate.add(res.status !== 200);
  sleep(1);
}
`;

return [{
  json: {
    ...aiAnalysisData,
    scripts: {
      loadTest: loadTestScript,
      stressTest: stressTestScript,
      spikeTest: spikeTestScript,
      enduranceTest: enduranceTestScript
    },
    executionOrder: ['loadTest', 'spikeTest', 'stressTest'],
    phase: 'nfr-scripts-generated'
  }
}];

// Aggregate test results from all NFR test executions
const loadTestResult = $('Execute Load Test').first()?.json || {};
const stressTestResult = $('Execute Stress Test').first()?.json || {};
const spikeTestResult = $('Execute Spike Test').first()?.json || {};

return [{
  json: {
    loadTestResults: loadTestResult,
    stressTestResults: stressTestResult,
    spikeTestResults: spikeTestResult,
    aggregatedAt: new Date().toISOString()
  }
}];

// Parse OpenAI API response for NFR performance analysis
const response = $input.first().json;

// Extract the message content from OpenAI response structure
const analysisContent = response.choices?.[0]?.message?.content || '{}';

let performanceAnalysis = {};
try {
  // Try to parse JSON from the response
  const jsonMatch = analysisContent.match(/```json\n?([\s\S]*?)\n?```/) || 
                    analysisContent.match(/\{[\s\S]*\}/);
  performanceAnalysis = JSON.parse(jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : analysisContent);
} catch (e) {
  // If parsing fails, structure the raw content
  performanceAnalysis = {
    performanceAnalysis: {},
    bottleneckIdentification: {},
    slaCompliance: {},
    recommendations: [],
    parseError: e.message,
    rawAnalysis: analysisContent
  };
}

// Get aggregated test results
const testResults = $('Aggregate NFR Test Results').first().json;

return [{
  json: {
    ...testResults,
    aiPerformanceAnalysis: performanceAnalysis,
    tokensUsed: response.usage?.total_tokens || 0,
    analysisComplete: true,
    timestamp: new Date().toISOString()
  }
}];

